function isValidTag(tag) {
  if (tag.length === 0) return false;
  for (let i = 0; i < tag.length; i++) {
    if (tag[i] === '-') {
      if (i === 0 || i === tag.length - 1) return false;
      if (tag[i - 1] === '-' || tag[i + 1] === '-') return false;
    }
  }
  return true;
}

